import Controller from"../../engine/Controller.js";export default class HomeController extends Controller{constructor(){super(),this.init()}async init(){await this.render("home"),this.setupEventListeners()}setupEventListeners(){console.log("Home Logic: Elements are now ready.")}setupHoverPreview(e){const t=document.querySelectorAll(".project-item"),r=document.querySelector(".featured-image"),o=document.querySelector(".featured-title");t.forEach(e=>{e.addEventListener("mouseenter",()=>{const t=e.getAttribute("data-name");o.innerText=t,r.src=`https://source.unsplash.com/featured/?${t.toLowerCase()},luxury`})})}}